    try:
        if "---" in content:
            # Split into thread tweets
            posts = [p.strip() for p in content.split("---") if p.strip()]
            result = create_thread(client, posts, publish_at=publish_at)
        else:
            result = create_draft(client, content, publish_at=publish_at)

